package com.hospital.management.controller.medical;import com.hospital.management.model.MedicalRecord;import com.hospital.management.service.*;import com.hospital.management.service.impl.MedicalRecordServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/medical-records/view")public class MedicalRecordViewServlet extends HttpServlet {private final MedicalRecordService service;public MedicalRecordViewServlet(){this(new MedicalRecordServiceImpl());}public MedicalRecordViewServlet(MedicalRecordService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=MedicalRequest.id(q.getParameter("id")),appointment=MedicalRequest.id(q.getParameter("appointmentId"));MedicalRecord record=id!=null?service.getRecord(id,MedicalRequest.user(q)).orElse(null):appointment!=null?service.getRecordByAppointment(appointment,MedicalRequest.user(q)).orElse(null):null;if(record==null){r.sendError(404);return;}q.setAttribute("record",record);q.getRequestDispatcher("/WEB-INF/views/medical-records/view.jsp").forward(q,r);}}
